using System.Globalization;

namespace Textualizer;

/// <summary>
/// Represents a data size with support for bits, bytes, kilobytes, megabytes,
/// gigabytes, and terabytes. Provides formatting, arithmetic, and comparison operations.
/// </summary>
public readonly struct DataSize :
    IComparable<DataSize>,
    IEquatable<DataSize>,
    IComparable,
    IFormattable
{
    public const string BitSymbol = "b";
    public const string ByteSymbol = "B";
    public const string KilobyteSymbol = "KB";
    public const string MegabyteSymbol = "MB";
    public const string GigabyteSymbol = "GB";
    public const string TerabyteSymbol = "TB";

    public const long BitsInByte = 8;
    public const long BytesInKilobyte = 1024;
    public const long BytesInMegabyte = 1_048_576;
    public const long BytesInGigabyte = 1_073_741_824;
    public const long BytesInTerabyte = 1_099_511_627_776;

    /// <summary>
    /// Gets the smallest possible <see cref="DataSize"/> value.
    /// </summary>
    public static readonly DataSize MinValue = FromBits(long.MinValue);

    /// <summary>
    /// Gets the largest possible <see cref="DataSize"/> value.
    /// </summary>
    public static readonly DataSize MaxValue = FromBits(long.MaxValue);

    /// <summary>
    /// Initializes a new instance of the <see cref="DataSize"/> struct with the specified number of bytes.
    /// </summary>
    /// <param name="byteSize">The size in bytes.</param>
    public DataSize(double byteSize)
    {
        Bits = (long)Math.Ceiling(byteSize * BitsInByte);
    }

    private DataSize(long bits)
    {
        Bits = bits;
    }

    /// <summary>Gets the number of bits.</summary>
    public long Bits { get; }

    /// <summary>Gets the number of bytes.</summary>
    public double Bytes => (double)Bits / BitsInByte;

    /// <summary>Gets the number of kilobytes.</summary>
    public double Kilobytes => (double)Bits / (BitsInByte * BytesInKilobyte);

    /// <summary>Gets the number of megabytes.</summary>
    public double Megabytes => (double)Bits / (BitsInByte * BytesInMegabyte);

    /// <summary>Gets the number of gigabytes.</summary>
    public double Gigabytes => (double)Bits / (BitsInByte * BytesInGigabyte);

    /// <summary>Gets the number of terabytes.</summary>
    public double Terabytes => (double)Bits / (BitsInByte * BytesInTerabyte);

    /// <summary>
    /// Gets the largest whole number unit symbol for this data size.
    /// </summary>
    public string LargestWholeNumberSymbol => GetLargestWholeUnit().Symbol;

    /// <summary>
    /// Gets the value in the largest whole number unit.
    /// </summary>
    public double LargestWholeNumberValue => GetLargestWholeUnit().Value;

    private (string Symbol, double Value) GetLargestWholeUnit()
    {
        // Check from largest to smallest unit
        double abs = Math.Abs(Bytes);
        if (abs >= BytesInTerabyte) return (TerabyteSymbol, Terabytes);
        if (abs >= BytesInGigabyte) return (GigabyteSymbol, Gigabytes);
        if (abs >= BytesInMegabyte) return (MegabyteSymbol, Megabytes);
        if (abs >= BytesInKilobyte) return (KilobyteSymbol, Kilobytes);
        if (abs >= 1) return (ByteSymbol, Bytes);
        return (BitSymbol, Bits);
    }

    // --- Factory methods ---

    /// <summary>Creates a <see cref="DataSize"/> from the specified number of bits.</summary>
    public static DataSize FromBits(long value) => new(value);

    /// <summary>Creates a <see cref="DataSize"/> from the specified number of bytes.</summary>
    public static DataSize FromBytes(double value) => new(value);

    /// <summary>Creates a <see cref="DataSize"/> from the specified number of kilobytes.</summary>
    public static DataSize FromKilobytes(double value) => new(value * BytesInKilobyte);

    /// <summary>Creates a <see cref="DataSize"/> from the specified number of megabytes.</summary>
    public static DataSize FromMegabytes(double value) => new(value * BytesInMegabyte);

    /// <summary>Creates a <see cref="DataSize"/> from the specified number of gigabytes.</summary>
    public static DataSize FromGigabytes(double value) => new(value * BytesInGigabyte);

    /// <summary>Creates a <see cref="DataSize"/> from the specified number of terabytes.</summary>
    public static DataSize FromTerabytes(double value) => new(value * BytesInTerabyte);

    // --- Arithmetic operators ---

    public static DataSize operator +(DataSize a, DataSize b) => new(a.Bits + b.Bits);
    public static DataSize operator -(DataSize a, DataSize b) => new(a.Bits - b.Bits);
    public static DataSize operator *(DataSize a, double b) => FromBytes(a.Bytes * b);
    public static DataSize operator /(DataSize a, double b) => FromBytes(a.Bytes / b);
    public static bool operator ==(DataSize a, DataSize b) => a.Bits == b.Bits;
    public static bool operator !=(DataSize a, DataSize b) => a.Bits != b.Bits;
    public static bool operator <(DataSize a, DataSize b) => a.Bits < b.Bits;
    public static bool operator >(DataSize a, DataSize b) => a.Bits > b.Bits;
    public static bool operator <=(DataSize a, DataSize b) => a.Bits <= b.Bits;
    public static bool operator >=(DataSize a, DataSize b) => a.Bits >= b.Bits;

    // --- IEquatable<DataSize> ---

    /// <inheritdoc />
    public bool Equals(DataSize other) => Bits == other.Bits;

    /// <inheritdoc />
    public override bool Equals(object? obj) => obj is DataSize other && Bits == other.Bits;

    /// <inheritdoc />
    public override int GetHashCode() => Bits.GetHashCode();

    // --- IComparable ---

    /// <inheritdoc />
    public int CompareTo(DataSize other) => Bits.CompareTo(other.Bits);

    /// <inheritdoc />
    public int CompareTo(object? obj) =>
        obj is DataSize other ? Bits.CompareTo(other.Bits) : throw new ArgumentException("Object is not a DataSize");

    // --- Formatting ---

    /// <summary>
    /// Returns a human-readable string representation using the largest whole number unit.
    /// </summary>
    public override string ToString() => ToString("0.##", CultureInfo.CurrentCulture);

    /// <summary>
    /// Returns a formatted string representation of this data size.
    /// </summary>
    /// <param name="format">A standard or custom numeric format string.</param>
    /// <param name="provider">An object that supplies culture-specific formatting information.</param>
    /// <returns>A formatted string representing this data size.</returns>
    public string ToString(string? format, IFormatProvider? formatProvider = null)
    {
        format ??= "0.## ";
        formatProvider ??= CultureInfo.CurrentCulture;

        if (!format.Contains('#') && !format.Contains('0'))
        {
            format = "0.## " + format;
        }

        if (format.Contains("#.##", StringComparison.Ordinal))
        {
            format = format.Replace("#.##", "0.##");
        }

        // Check for explicit unit symbols in the format string (longest match first).
        // All comparisons use ordinal case-insensitive matching for consistency.
        if (TryFormatWithUnit(format, TerabyteSymbol, Terabytes, formatProvider, out var result)) return result;
        if (TryFormatWithUnit(format, GigabyteSymbol, Gigabytes, formatProvider, out result)) return result;
        if (TryFormatWithUnit(format, MegabyteSymbol, Megabytes, formatProvider, out result)) return result;
        if (TryFormatWithUnit(format, KilobyteSymbol, Kilobytes, formatProvider, out result)) return result;
        if (TryFormatWithUnit(format, ByteSymbol, Bytes, formatProvider, out result)) return result;
        if (TryFormatWithUnit(format, BitSymbol, Bits, formatProvider, out result)) return result;

        var (symbol, value) = GetLargestWholeUnit();
        return string.Concat(value.ToString(format, formatProvider), " ", symbol);
    }

    private static bool TryFormatWithUnit(
        string format, string unitSymbol, double value,
        IFormatProvider formatProvider, out string result)
    {
        int idx = format.IndexOf(unitSymbol, StringComparison.OrdinalIgnoreCase);
        if (idx < 0)
        {
            result = "";
            return false;
        }

        // Strip the unit symbol from the numeric format, keeping any surrounding text
        string numericFormat = string.Concat(format.AsSpan(0, idx), format.AsSpan(idx + unitSymbol.Length));
        result = string.Concat(value.ToString(numericFormat, formatProvider), unitSymbol);
        return true;
    }

    /// <summary>
    /// Parses a string representation into a <see cref="DataSize"/> value.
    /// Supports formats like "1.5 GB", "500 MB", "2TB", "8192b".
    /// </summary>
    /// <param name="input">The string to parse.</param>
    /// <returns>A <see cref="DataSize"/> value.</returns>
    /// <exception cref="FormatException">Thrown when the input cannot be parsed.</exception>
    public static DataSize Parse(string input)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(input);

        input = input.Trim();

        // Try multi-char suffixes first (longest match), then single-char.
        // This prevents "B" matching the trailing char of "KB"/"MB"/"GB"/"TB".
        if (TryParseWithSuffix(input, TerabyteSymbol, out var tb)) return FromTerabytes(tb);
        if (TryParseWithSuffix(input, GigabyteSymbol, out var gb)) return FromGigabytes(gb);
        if (TryParseWithSuffix(input, MegabyteSymbol, out var mb)) return FromMegabytes(mb);
        if (TryParseWithSuffix(input, KilobyteSymbol, out var kb)) return FromKilobytes(kb);

        // For single-char suffixes, use case-sensitive matching to distinguish "B" (bytes) from "b" (bits)
        if (TryParseWithSuffix(input, ByteSymbol, out var b, StringComparison.Ordinal)) return FromBytes(b);
        if (TryParseWithSuffix(input, BitSymbol, out var bits, StringComparison.Ordinal)) return FromBits((long)bits);

        if (double.TryParse(input, out var bytes))
        {
            return FromBytes(bytes);
        }

        throw new FormatException($"Unable to parse '{input}' as a data size.");
    }

    private static bool TryParseWithSuffix(
        string input, string suffix, out double value,
        StringComparison comparison = StringComparison.OrdinalIgnoreCase)
    {
        value = 0;
        if (input.EndsWith(suffix, comparison))
        {
            var numericPart = input.AsSpan(0, input.Length - suffix.Length).Trim();
            return double.TryParse(numericPart, NumberStyles.Float, CultureInfo.InvariantCulture, out value);
        }

        return false;
    }
}

