4. 
5. /// <summary>
6. /// Represents a data size with support for bits, bytes, kilobytes, megabytes,
7. /// gigabytes, and terabytes. Provides formatting, arithmetic, and comparison operations.
8. /// </summary>
9. public readonly struct DataSize :
10.     IComparable<DataSize>,
11.     IEquatable<DataSize>,
12.     IComparable,
13.     IFormattable
14. {
15.     public const string BitSymbol = "b";
16.     public const string ByteSymbol = "B";
17.     public const string KilobyteSymbol = "KB";
18.     public const string MegabyteSymbol = "MB";
19.     public const string GigabyteSymbol = "GB";
20.     public const string TerabyteSymbol = "TB";
21. 
22.     public const long BitsInByte = 8;
23.     public const long BytesInKilobyte = 1024;
24.     public const long BytesInMegabyte = 1_048_576;
25.     public const long BytesInGigabyte = 1_073_741_824;
26.     public const long BytesInTerabyte = 1_099_511_627_776;
27. 
28.     /// <summary>
29.     /// Gets the smallest possible <see cref="DataSize"/> value.
30.     /// </summary>
31.     public static readonly DataSize MinValue = FromBits(long.MinValue);
32. 
33.     /// <summary>
34.     /// Gets the largest possible <see cref="DataSize"/> value.
35.     /// </summary>
36.     public static readonly DataSize MaxValue = FromBits(long.MaxValue);
37. 
38.     /// <summary>
39.     /// Initializes a new instance of the <see cref="DataSize"/> struct with the specified number of bytes.
40.     /// </summary>
41.     /// <param name="byteSize">The size in bytes.</param>
42.     public DataSize(double byteSize)
43.     {
44.         Bits = (long)Math.Ceiling(byteSize * BitsInByte);
45.     }
46. 
47.     private DataSize(long bits)
48.     {
49.         Bits = bits;
50.     }
51. 
52.     /// <summary>Gets the number of bits.</summary>
53.     public long Bits { get; }
54. 
55.     /// <summary>Gets the number of bytes.</summary>
56.     public double Bytes => (double)Bits / BitsInByte;
57. 
58.     /// <summary>Gets the number of kilobytes.</summary>
59.     public double Kilobytes => (double)Bits / (BitsInByte * BytesInKilobyte);
60. 
61.     /// <summary>Gets the number of megabytes.</summary>
62.     public double Megabytes => (double)Bits / (BitsInByte * BytesInMegabyte);
63. 
64.     /// <summary>Gets the number of gigabytes.</summary>
65.     public double Gigabytes => (double)Bits / (BitsInByte * BytesInGigabyte);
66. 
67.     /// <summary>Gets the number of terabytes.</summary>
68.     public double Terabytes => (double)Bits / (BitsInByte * BytesInTerabyte);
69. 
70.     /// <summary>
71.     /// Gets the largest whole number unit symbol for this data size.
72.     /// </summary>
73.     public string LargestWholeNumberSymbol => GetLargestWholeUnit().Symbol;
74. 
75.     /// <summary>
76.     /// Gets the value in the largest whole number unit.
77.     /// </summary>
78.     public double LargestWholeNumberValue => GetLargestWholeUnit().Value;
79. 
80.     private (string Symbol, double Value) GetLargestWholeUnit()
81.     {
82.         // Check from largest to smallest unit
83.         double abs = Math.Abs(Bytes);
84.         if (abs >= BytesInTerabyte) return (TerabyteSymbol, Terabytes);
85.         if (abs >= BytesInGigabyte) return (GigabyteSymbol, Gigabytes);
86.         if (abs >= BytesInMegabyte) return (MegabyteSymbol, Megabytes);
87.         if (abs >= BytesInKilobyte) return (KilobyteSymbol, Kilobytes);
88.         if (abs >= 1) return (ByteSymbol, Bytes);
89.         return (BitSymbol, Bits);
90.     }
