95.     public static DataSize FromBits(long value) => new(value);
96. 
97.     /// <summary>Creates a <see cref="DataSize"/> from the specified number of bytes.</summary>
98.     public static DataSize FromBytes(double value) => new(value);
99. 
100.     /// <summary>Creates a <see cref="DataSize"/> from the specified number of kilobytes.</summary>
101.     public static DataSize FromKilobytes(double value) => new(value * BytesInKilobyte);
102. 
103.     /// <summary>Creates a <see cref="DataSize"/> from the specified number of megabytes.</summary>
104.     public static DataSize FromMegabytes(double value) => new(value * BytesInMegabyte);
105. 
106.     /// <summary>Creates a <see cref="DataSize"/> from the specified number of gigabytes.</summary>
107.     public static DataSize FromGigabytes(double value) => new(value * BytesInGigabyte);
108. 
109.     /// <summary>Creates a <see cref="DataSize"/> from the specified number of terabytes.</summary>
110.     public static DataSize FromTerabytes(double value) => new(value * BytesInTerabyte);
111. 
112.     // --- Arithmetic operators ---
