114.     public static DataSize operator +(DataSize a, DataSize b) => new(a.Bits + b.Bits);
115.     public static DataSize operator -(DataSize a, DataSize b) => new(a.Bits - b.Bits);
116.     public static DataSize operator *(DataSize a, double b) => FromBytes(a.Bytes * b);
117.     public static DataSize operator /(DataSize a, double b) => FromBytes(a.Bytes / b);
118.     public static bool operator ==(DataSize a, DataSize b) => a.Bits == b.Bits;
119.     public static bool operator !=(DataSize a, DataSize b) => a.Bits != b.Bits;
120.     public static bool operator <(DataSize a, DataSize b) => a.Bits < b.Bits;
121.     public static bool operator >(DataSize a, DataSize b) => a.Bits > b.Bits;
122.     public static bool operator <=(DataSize a, DataSize b) => a.Bits <= b.Bits;
123.     public static bool operator >=(DataSize a, DataSize b) => a.Bits >= b.Bits;
