156.     /// <param name="provider">An object that supplies culture-specific formatting information.</param>
157.     /// <returns>A formatted string representing this data size.</returns>
158.     public string ToString(string? format, IFormatProvider? formatProvider = null)
159.     {
160.         format ??= "0.## ";
161.         formatProvider ??= CultureInfo.CurrentCulture;
162. 
163.         if (!format.Contains('#') && !format.Contains('0'))
164.         {
165.             format = "0.## " + format;
166.         }
167. 
168.         if (format.Contains("#.##", StringComparison.Ordinal))
169.         {
170.             format = format.Replace("#.##", "0.##");
171.         }
172. 
173.         // Check for explicit unit symbols in the format string (longest match first).
174.         // All comparisons use ordinal case-insensitive matching for consistency.
175.         if (TryFormatWithUnit(format, TerabyteSymbol, Terabytes, formatProvider, out var result)) return result;
176.         if (TryFormatWithUnit(format, GigabyteSymbol, Gigabytes, formatProvider, out result)) return result;
177.         if (TryFormatWithUnit(format, MegabyteSymbol, Megabytes, formatProvider, out result)) return result;
178.         if (TryFormatWithUnit(format, KilobyteSymbol, Kilobytes, formatProvider, out result)) return result;
179.         if (TryFormatWithUnit(format, ByteSymbol, Bytes, formatProvider, out result)) return result;
180.         if (TryFormatWithUnit(format, BitSymbol, Bits, formatProvider, out result)) return result;
181. 
182.         var (symbol, value) = GetLargestWholeUnit();
183.         return string.Concat(value.ToString(format, formatProvider), " ", symbol);
184.     }
